  ('aboriginal-c5fb3965-moex-00298', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-110-bdc7da1c', 'sub-aboriginal-c5fb3965-02', NULL, 'single_choice', '下列何者非屬原住民得申請喪失原住民身分之事由？', '["原住民與非原住民結婚者", "遷出原住民戶籍所在地2年以上", "年滿20歲，自願拋棄原住民身分者", "原住民為非原住民收養者"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:06+00:00", "source_pdf_sha1": "4872a7c22515", "answer_pdf_sha1": "42cd6b1843cb", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "603", "s": "0611", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "戶籍法規大意", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 48, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00299', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-110-bdc7da1c', 'sub-aboriginal-c5fb3965-02', NULL, 'single_choice', '有關原住民身分登記之更正，下列敘述何者錯誤？', '["須更正的情形包括誤登記或漏未登記為原住民身分", "當事人得向戶籍所在地之戶政事務所申請查明，並為更正之登記", "全國任一戶政事務所知悉有登記錯誤的情事，應即為更正登記", "當事人戶籍所在地之戶政事務所知悉錯誤即應書面通知當事人為更正之登記"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:06+00:00", "source_pdf_sha1": "4872a7c22515", "answer_pdf_sha1": "42cd6b1843cb", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "603", "s": "0611", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "戶籍法規大意", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 49, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00300', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-110-bdc7da1c', 'sub-aboriginal-c5fb3965-02', NULL, 'single_choice', '山地原住民甲與平地原住民乙結婚，有關甲乙二人及其子女之身分，下列何者不符原住民身分法規定？', '["甲乙結婚並不影響各自山地或平地原住民之身分", "甲乙得約定共同為山地原住民之身分", "甲乙結婚時未約定相同之山地或平地原住民身分，仍得協議其未成年子女取得山地或平地原住民身分", "甲乙結婚時已約定相同之平地原住民身分，其子女成年後得申請變更為山地原住民身分"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:06+00:00", "source_pdf_sha1": "4872a7c22515", "answer_pdf_sha1": "42cd6b1843cb", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "603", "s": "0611", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "戶籍法規大意", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 50, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00301', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-110-55d283b0', 'sub-aboriginal-c5fb3965-03', NULL, 'single_choice', '命令定有施行期限，主管機關認為需要延長者，其應如何處理：', '["應於施行期限屆滿之日後，由原發布機關發布延長", "應於施行期限屆滿1個月前，由原發布機關發布延長", "應於施行期限屆滿2個月前，由原發布機關發布延長", "應於施行期限屆滿3個月前，由原發布機關發布延長"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:06+00:00", "source_pdf_sha1": "93382b4aec10", "answer_pdf_sha1": "56bfa56d5fe2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "603", "s": "0610", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00302', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-110-55d283b0', 'sub-aboriginal-c5fb3965-03', NULL, 'single_choice', '依地方制度法，關於地方自治法規，下列敘述何者錯誤？', '["直轄市、縣（市）、鄉（鎮、市）得就其自治事項制定自治法規", "直轄市、縣（市）、鄉（鎮、市）得依上級法規之授權，制定自治法規", "自治法規得由地方立法機關通過，並由各該行政機關公布", "自治法規由地方行政機關訂定，並發布或下達者，稱自治條例"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:06+00:00", "source_pdf_sha1": "93382b4aec10", "answer_pdf_sha1": "56bfa56d5fe2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "603", "s": "0610", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00303', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-110-55d283b0', 'sub-aboriginal-c5fb3965-03', NULL, 'single_choice', 'A於黑夜駕車不慎撞傷穿越馬路之B，如認A對B應負民事賠償責任，有關其法律適用的三段論法， 下列敘述何者正確？', '["大前提是指確立所應適用的法律規範，如民法第184條第1項規定", "小前提是指對於大前提中法律要件的內涵確定，因此必須探查諸如故意、過失、權利之意涵", "小前提是個案違法性的確立，必須判斷A撞傷B的行為具有違法性，始進入下一步驟的檢驗", "第三段是在確立有責性，A在確認有責性之後才負有民事責任"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:06+00:00", "source_pdf_sha1": "93382b4aec10", "answer_pdf_sha1": "56bfa56d5fe2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "603", "s": "0610", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00304', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-110-55d283b0', 'sub-aboriginal-c5fb3965-03', NULL, 'single_choice', '下列何者屬於法律之「擬制」？', '["時效因開始執行行為而中斷者，若因權利人之聲請或法律上要件之欠缺，而撤銷其執行處分時，視 為不中斷", "對話為要約者，非立時承諾，即失其拘束力", "當事人互相表示意思一致者，無論其為明示或默示，契約即為成立", "契約當事人約定其契約須用一定方式者，在該方式未完成前，推定其契約不成立"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:06+00:00", "source_pdf_sha1": "93382b4aec10", "answer_pdf_sha1": "56bfa56d5fe2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "603", "s": "0610", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00305', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-110-55d283b0', 'sub-aboriginal-c5fb3965-03', NULL, 'single_choice', '法律解釋的方法，通常可區分為文義解釋、體系解釋、歷史解釋、目的解釋等，應以何種方法為優先？', '["文義解釋", "體系解釋", "歷史解釋", "視實際需要而定，並無特定之優先順序"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:06+00:00", "source_pdf_sha1": "93382b4aec10", "answer_pdf_sha1": "56bfa56d5fe2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "603", "s": "0610", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00306', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-110-55d283b0', 'sub-aboriginal-c5fb3965-03', NULL, 'single_choice', '法院受理之案件，一經繫屬或裁判確定，當事人不得對之再為同一訴訟，此原則稱為：', '["武器平等原則", "告訴乃論", "一事不再理原則", "時效消滅"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:06+00:00", "source_pdf_sha1": "93382b4aec10", "answer_pdf_sha1": "56bfa56d5fe2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "603", "s": "0610", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00307', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-110-55d283b0', 'sub-aboriginal-c5fb3965-03', NULL, 'single_choice', '依憲法增修條文規定，下列何者不屬於監察院之職權？', '["彈劾權", "審計權", "人事同意權", "糾舉權"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:06+00:00", "source_pdf_sha1": "93382b4aec10", "answer_pdf_sha1": "56bfa56d5fe2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "603", "s": "0610", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL)
